import { core } from "@pulumi/oci";
import { Config } from "@pulumi/pulumi";

import { configureAppInstance } from "./app";
import { configureDatabaseInstance } from "./db";

// -----

const config = new Config();

const compartmentId = config.require("ocid");
const sshPublicKey = config.require("sshPublicKey");
const dbCredentials = {
  NAME: config.require("db_name"),
  PASSWORD: config.requireSecret("db_password"),
  USER: config.require("db_user"),
};

// -----

import { core, identity } from "@pulumi/oci";
import type { InternetGateway, Vcn } from "@pulumi/oci/core";

export function configureAppInstance(
  {
    sshPublicKey,
  }: {
    sshPublicKey: string;
    dbPrivateIp: string;
    appDomain: string;
    repoUrl: string;
    repoBranch: string;
  },
  {
    igw,
    vcn,
    compartmentId,
  }: {
    compartmentId: string;
    igw: InternetGateway;

import { core, identity } from "@pulumi/oci";
import type { InternetGateway, Vcn } from "@pulumi/oci/core";
import type { Output } from "@pulumi/pulumi";

export function configureDatabaseInstance(
  {
    dbCredentials,
    sshPublicKey,
  }: {
    sshPublicKey: string;
    dbCredentials: {
      NAME: string;
      PASSWORD: Output<string>;
      USER: string;
    };
  },
  {
    compartmentId,
    vcn,
    igw,

import { config } from "dotenv";
import { defineConfig } from "drizzle-kit";

config({ path: [".env.local", ".env"] });

export default defineConfig({
  dbCredentials: {
    url: process.env.DATABASE_URL || "",
  },
  dialect: "postgresql",
  out: "./drizzle",
  schema: "./src/db-schemas",
});

