import * as pulumi from "@pulumi/pulumi";
import { core, identity } from "@pulumi/oci";
import type { InternetGateway, Vcn } from "@pulumi/oci/core";
import type { Output } from "@pulumi/pulumi";

export interface InstanceArgs {
  sshPublicKey: string;
  appDomain: string;
  appImage: string;
  ghcrPat: Output<string>;
  dbCredentials: {
    NAME: string;
    PASSWORD: Output<string>;
    USER: string;
  };
  betterAuthSecret: Output<string>;
  betterAuthUrl: string;
  r2AccessKeyId: string;
  r2SecretAccessKey: Output<string>;
  r2AccountId: string;
  r2BucketName: string;
  r2PublicUrl: string;
  publicPosthogKey?: string;
  publicPosthogHost?: string;
}

export function configureInstance(
  args: InstanceArgs,
  {
    compartmentId,
    igw,
    vcn,
  }: {
    compartmentId: string;
    igw: InternetGateway;
    vcn: Vcn;
  },
) {
  const routeTable = new core.RouteTable("main-rt", {
    compartmentId,
    displayName: "main-rt",
    routeRules: [{ destination: "0.0.0.0/0", networkEntityId: igw.id }],
    vcnId: vcn.id,
  });

  const securityList = new core.SecurityList("main-sl", {
    compartmentId,
    displayName: "main-sl",
    egressSecurityRules: [{ destination: "0.0.0.0/0", protocol: "all" }],
    ingressSecurityRules: [
      {
        protocol: "6",
        source: "0.0.0.0/0",
        tcpOptions: { sourcePortRange: { max: 22, min: 22 } },
      },
      {
        protocol: "6",
        source: "0.0.0.0/0",
        tcpOptions: { sourcePortRange: { max: 80, min: 80 } },
      },
      {
        protocol: "6",
        source: "0.0.0.0/0",
        tcpOptions: { sourcePortRange: { max: 443, min: 443 } },
      },
    ],
    vcnId: vcn.id,
  });

  const subnet = new core.Subnet("main-subnet", {
    cidrBlock: "10.0.1.0/24",
    compartmentId,
    displayName: "main-subnet",
    dnsLabel: "mainsub",
    routeTableId: routeTable.id,
    securityListIds: [securityList.id],
    vcnId: vcn.id,
  });

  const ads = identity.getAvailabilityDomainsOutput({ compartmentId });

  const images = core.getImagesOutput({
    compartmentId,
    operatingSystem: "Canonical Ubuntu",
    operatingSystemVersion: "22.04",
    shape: "VM.Standard.A1.Flex",
  });

  const userData = pulumi
    .all([
      args.dbCredentials.PASSWORD,
      args.betterAuthSecret,
      args.r2SecretAccessKey,
      args.ghcrPat,
    ])
    .apply(([dbPw, authSecret, r2Secret, ghcrPat]) => {
      const caddyBlock = args.appDomain
        ? `${args.appDomain} {\n  reverse_proxy app:3020\n}`
        : `:80 {\n  reverse_proxy app:3020\n}`;

      const envLines = [
        `APP_IMAGE=${args.appImage}`,
        `DB_USER=${args.dbCredentials.USER}`,
        `DB_PASSWORD=REDACTED,
        `DB_NAME=${args.dbCredentials.NAME}`,
        `BETTER_AUTH_SECRET=${authSecret}`,
        `BETTER_AUTH_URL=${args.betterAuthUrl}`,
        `R2_ACCESS_KEY_ID=${args.r2AccessKeyId}`,
        `R2_SECRET_ACCESS_KEY=${r2Secret}`,
        `R2_ACCOUNT_ID=${args.r2AccountId}`,
        `R2_BUCKET_NAME=${args.r2BucketName}`,
        `PUBLIC_R2_PUBLIC_URL=${args.r2PublicUrl}`,
      ];

      if (args.publicPosthogKey) {
        envLines.push(`PUBLIC_POSTHOG_KEY=${args.publicPosthogKey}`);
      }
      if (args.publicPosthogHost) {
        envLines.push(`PUBLIC_POSTHOG_HOST=${args.publicPosthogHost}`);
      }

      const cloudInit = `#cloud-config
package_update: true
package_upgrade: true

packages:
  - curl
  - ufw
  - ca-certificates
  - gnupg

write_files:
  - path: /opt/alpauls-ats/docker-compose.yml
    content: |
      name: alpauls-ats

      services:
        db:
          image: postgres:18-alpine
          restart: always
          environment:
            POSTGRES_USER: \${DB_USER}
            POSTGRES_PASSWORD: \${DB_PASSWORD}
            POSTGRES_DB: \${DB_NAME}
          volumes:
            - db-data:/var/lib/postgresql/18/data
          healthcheck:
            test: ["CMD-SHELL", "pg_isready -U \${DB_USER}"]
            interval: 5s
            timeout: 5s
            retries: 5
          networks:
            - alpauls-net

        app:
          image: \${APP_IMAGE}
          restart: always
          depends_on:
            db:
              condition: service_healthy
          environment:
            DATABASE_URL: REDACTED
            BETTER_AUTH_SECRET: \${BETTER_AUTH_SECRET}
            BETTER_AUTH_URL: \${BETTER_AUTH_URL}
            R2_ACCESS_KEY_ID: \${R2_ACCESS_KEY_ID}
            R2_SECRET_ACCESS_KEY: \${R2_SECRET_ACCESS_KEY}
            R2_ACCOUNT_ID: \${R2_ACCOUNT_ID}
            R2_BUCKET_NAME: \${R2_BUCKET_NAME}
            PUBLIC_R2_PUBLIC_URL: \${PUBLIC_R2_PUBLIC_URL}
            PUBLIC_POSTHOG_KEY: \${PUBLIC_POSTHOG_KEY:-}
            PUBLIC_POSTHOG_HOST: \${PUBLIC_POSTHOG_HOST:-}
          networks:
            - alpauls-net

        caddy:
          image: caddy:2-alpine
          restart: always
          ports:
            - "80:80"
            - "443:443"
          volumes:
            - ./Caddyfile:/etc/caddy/Caddyfile:ro
            - caddy-data:/data
            - caddy-config:/config
          depends_on:
            - app
          networks:
            - alpauls-net

      volumes:
        db-data:
        caddy-data:
        caddy-config:

      networks:
        alpauls-net:
          driver: bridge
    owner: root:root
    permissions: "0644"
  - path: /opt/alpauls-ats/Caddyfile
    content: |
      ${caddyBlock}
    owner: root:root
    permissions: "0644"
  - path: /opt/alpauls-ats/.env
    content: |
      ${envLines.join("\n")}
    owner: root:root
    permissions: "0600"

runcmd:
  - install -m 0755 -d /etc/apt/keyrings
  - curl -fsSL https://download.docker.com/linux/ubuntu/gpg | gpg --dearmor -o /etc/apt/keyrings/docker.gpg
  - echo "deb [arch=arm64 signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu $(lsb_release -cs) stable" > /etc/apt/sources.list.d/docker.list
  - apt-get update
  - apt-get install -y docker-ce docker-ce-cli containerd.io docker-compose-plugin
  - systemctl enable docker
  - systemctl start docker
  - echo '${ghcrPat}' | docker login ghcr.io -u '_' --password-stdin
  - cd /opt/alpauls-ats && docker compose --env-file .env up -d
  - ufw allow 22/tcp
  - ufw allow 80/tcp
  - ufw allow 443/tcp
  - ufw --force enable
`;
      return Buffer.from(cloudInit).toString("base64");
    });

  const instance = new core.Instance("main-vm", {
    availabilityDomain: ads.availabilityDomains[0].name,
    compartmentId,
    createVnicDetails: {
      assignPublicIp: "true",
      hostnameLabel: "main",
      privateIp: "10.0.1.10",
      subnetId: subnet.id,
    },
    displayName: "alpauls-ats",
    metadata: {
      ssh_authorized_keys: args.sshPublicKey,
      user_data: userData,
    },
    shape: "VM.Standard.A1.Flex",
    shapeConfig: {
      memoryInGbs: 8,
      ocpus: 2,
    },
    sourceDetails: {
      bootVolumeSizeInGbs: 50,
      imageId: images.id,
      sourceType: "image",
    },
  });

  return { instance };
}

