import { core } from "@pulumi/oci";
import { Config } from "@pulumi/pulumi";

import { configureInstance } from "./app";

const config = new Config();

const compartmentId = config.require("ocid");
const sshPublicKey = config.require("sshPublicKey");
const dbCredentials = {
  NAME: config.require("db_name"),
  PASSWORD: config.requireSecret("db_password"),
  USER: config.require("db_user"),
};

const vcn = new core.Vcn("alpauls-ats-vcn", {
  cidrBlocks: ["10.0.0.0/16"],
  compartmentId,
  displayName: "alpauls-ats-vcn",
  dnsLabel: "alpauls-ats",
});

const igw = new core.InternetGateway("alpauls-ats-igw", {
  compartmentId,
  displayName: "alpauls-ats-igw",
  enabled: true,
  vcnId: vcn.id,
});

configureInstance(
  {
    sshPublicKey,
    appDomain: config.require("app_domain"),
    appImage: config.require("app_image"),
    ghcrPat: config.requireSecret("ghcr_pat"),
    dbCredentials,
    betterAuthSecret: config.requireSecret("better_auth_secret"),
    betterAuthUrl: config.require("better_auth_url"),
    r2AccessKeyId: config.require("r2_access_key_id"),
    r2SecretAccessKey: config.requireSecret("r2_secret_access_key"),
    r2AccountId: config.require("r2_account_id"),
    r2BucketName: config.require("r2_bucket_name"),
    r2PublicUrl: config.require("r2_public_url"),
    publicPosthogKey: config.get("public_posthog_key"),
    publicPosthogHost: config.get("public_posthog_host"),
  },
  { compartmentId, igw, vcn },
);

