export interface ServiceConfig {
  image: string;
  restart: string;
  environment: Record<string, string>;
  volumes?: string[];
  ports?: string[];
  depends_on?: string[];
  healthcheck?: {
    test: string[];
    interval: string;
    timeout: string;
    retries: number;
  };
}

// biome-ignore-start suspicious/noTemplateCurlyInString: Docker Compose variable substitution placeholders
export const dbService: ServiceConfig = {
  image: "postgres:18-alpine",
  restart: "always",
  environment: {
    POSTGRES_USER: "${DB_USER}",
    POSTGRES_PASSWORD: "${DB_PASSWORD}",
    POSTGRES_DB: "${DB_NAME}",
  },
  volumes: ["db-data:/var/lib/postgresql/18/data"],
  healthcheck: {
    test: ["CMD-SHELL", "pg_isready -U ${DB_USER}"],
    interval: "5s",
    timeout: "5s",
    retries: 5,
  },
};

export const appService: ServiceConfig = {
  image: "${APP_IMAGE}",
  restart: "always",
  environment: {
    DATABASE_URL: "REDACTED",
